function structureOnly(node) {
  if (Array.isArray(node)) return node.map(structureOnly);
  if (node && typeof node === "object") {
    return Object.fromEntries(
      Object.entries(node).filter(([k]) => k !== "description").map(([k, v]) => [k, structureOnly(v)])
    );
  }
  return node;
}
