function enrichComputedForAudit(measure, library2) {
  const a = measure.abatement;
  if (!a?.computed?.formula_ref) return measure;
  const ref = a.computed.formula_ref;
  const tmpl = library2.formulaTemplates[ref];
  if (!tmpl) {
    return { ...measure, abatement: { ...a, computed: {
      ...a.computed,
      formula_resolution_error: `Unknown formula template '${ref}' (not in library.formulaTemplates).`
    } } };
  }
  try {
    const resolved_ast = bindTemplateSymbolic(tmpl, a.computed.bindings);
    const human = renderAst(resolved_ast, (k) => k);
    return { ...measure, abatement: { ...a, computed: {
      ...a.computed,
      formula: tmpl,
      resolved_ast,
      human
    } } };
  } catch (e) {
    return { ...measure, abatement: { ...a, computed: {
      ...a.computed,
      formula: tmpl,
      formula_resolution_error: e.message
    } } };
  }
}
